import{_ as a,b as r,e as n,al as d}from"./chunks/framework.DrQIcdFj.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var e=new t.Error().stack;e&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[e]="0400289e-3322-40d1-ac22-1d67261a2bd6",t._sentryDebugIdIdentifier="sentry-dbid-0400289e-3322-40d1-ac22-1d67261a2bd6")}catch{}})();const h=JSON.parse('{"title":"设计模式终极总结","description":"","frontmatter":{},"headers":[],"relativePath":"designPatterns/summary/patternSummarize.md","filePath":"designPatterns/summary/patternSummarize.md","lastUpdated":null}'),s={name:"designPatterns/summary/patternSummarize.md"};function o(t,e,l,i,g,f){return r(),n("div",null,[...e[0]||(e[0]=[d('<h1 id="设计模式终极总结" tabindex="-1">设计模式终极总结 <a class="header-anchor" href="#设计模式终极总结" aria-label="Permalink to &quot;设计模式终极总结&quot;">​</a></h1><h2 id="_1-模式全景回顾图" tabindex="-1">1. 模式全景回顾图 <a class="header-anchor" href="#_1-模式全景回顾图" aria-label="Permalink to &quot;1. 模式全景回顾图&quot;">​</a></h2><p>我们按照模式解决的<strong>核心问题</strong>进行分类总结：</p><h3 id="_1-1-创建型-creational-——-如何优雅地创建对象" tabindex="-1">1.1 创建型 (Creational) —— “如何优雅地创建对象？” <a class="header-anchor" href="#_1-1-创建型-creational-——-如何优雅地创建对象" aria-label="Permalink to &quot;1.1 创建型 (Creational) —— “如何优雅地创建对象？”&quot;">​</a></h3><p>主要解决直接使用 <code>new</code> 带来的强耦合问题。</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式名称</th><th style="text-align:left;">核心口诀</th><th style="text-align:left;">经典实战场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>单例模式</strong></td><td style="text-align:left;">“天无二日”：保证全局只有一个实例。</td><td style="text-align:left;">Redux/Vuex 的 Store，全局唯一的 Loading 弹窗。</td></tr><tr><td style="text-align:left;"><strong>工厂模式</strong></td><td style="text-align:left;">“代客下单”：隐藏 <code>new</code> 细节，根据参数返回对象。</td><td style="text-align:left;">UI 组件库的动态实例化（如 <code>Message.success()</code>）。</td></tr><tr><td style="text-align:left;"><strong>构造器模式</strong></td><td style="text-align:left;">“批量生产”：提供对象初始化的蓝图。</td><td style="text-align:left;">ES6 的 <code>class</code> 定义。</td></tr><tr><td style="text-align:left;"><strong>原型模式</strong></td><td style="text-align:left;">“克隆分裂”：基于现有对象克隆出新对象。</td><td style="text-align:left;">JavaScript 原生继承机制的基础。</td></tr></tbody></table><h3 id="_1-2-结构型-structural-——-如何把对象组装起来" tabindex="-1">1.2 结构型 (Structural) —— “如何把对象组装起来？” <a class="header-anchor" href="#_1-2-结构型-structural-——-如何把对象组装起来" aria-label="Permalink to &quot;1.2 结构型 (Structural) —— “如何把对象组装起来？”&quot;">​</a></h3><p>主要解决对象之间的依赖关系，如何让它们更好地协同工作。</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式名称</th><th style="text-align:left;">核心口诀</th><th style="text-align:left;">经典实战场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>代理模式</strong></td><td style="text-align:left;">“前台秘书”：拦截访问，代为处理。</td><td style="text-align:left;"><strong>Vue 3 响应式原理 (Proxy)</strong>、防抖节流函数。</td></tr><tr><td style="text-align:left;"><strong>装饰器模式</strong></td><td style="text-align:left;">“手机加壳”：不改源码，动态叠加新功能。</td><td style="text-align:left;">React 的 HOC（高阶组件）、埋点日志记录。</td></tr><tr><td style="text-align:left;"><strong>适配器模式</strong></td><td style="text-align:left;">“电源转换头”：抹平两个不兼容接口的差异。</td><td style="text-align:left;">兼容旧版 SDK、转换后端返回的怪异数据格式。</td></tr><tr><td style="text-align:left;"><strong>外观模式</strong></td><td style="text-align:left;">“一键全屋智能”：把复杂子系统封装成简单 API。</td><td style="text-align:left;"><code>jQuery</code> 的 <code>$.ajax</code>（屏蔽了各种浏览器的差异）。</td></tr><tr><td style="text-align:left;"><strong>组合模式</strong></td><td style="text-align:left;">“俄罗斯套娃”：树形结构，部分和整体一致对待。</td><td style="text-align:left;">文件夹遍历、DOM 树渲染。</td></tr><tr><td style="text-align:left;"><strong>享元模式</strong></td><td style="text-align:left;">“共享单车”：抽取公共状态，极大节省内存。</td><td style="text-align:left;"><strong>长列表的虚拟滚动</strong>、对象池。</td></tr></tbody></table><h3 id="_1-3-行为型-behavioral-——-对象之间如何沟通与分配职责" tabindex="-1">1.3 行为型 (Behavioral) —— “对象之间如何沟通与分配职责？” <a class="header-anchor" href="#_1-3-行为型-behavioral-——-对象之间如何沟通与分配职责" aria-label="Permalink to &quot;1.3 行为型 (Behavioral) —— “对象之间如何沟通与分配职责？”&quot;">​</a></h3><p>主要解决复杂的业务流转和状态管理。</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式名称</th><th style="text-align:left;">核心口诀</th><th style="text-align:left;">经典实战场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>观察者模式</strong></td><td style="text-align:left;">“订报纸”：目标变化，自动挨个通知观察者。</td><td style="text-align:left;"><strong>Vue 2 响应式原理 (<code>Dep</code> 与 <code>Watcher</code>)</strong>。</td></tr><tr><td style="text-align:left;"><strong>发布-订阅</strong></td><td style="text-align:left;">“中间商赚差价”：完全解耦，靠调度中心传话。</td><td style="text-align:left;"><strong>Event Bus (全局事件总线)</strong>。</td></tr><tr><td style="text-align:left;"><strong>策略模式</strong></td><td style="text-align:left;">“锦囊妙计”：封装算法，消除 <code>if-else</code>。</td><td style="text-align:left;">表单的多重校验规则、不同 VIP 等级的计费算法。</td></tr><tr><td style="text-align:left;"><strong>状态模式</strong></td><td style="text-align:left;">“变色龙”：将复杂的状态流转拆分到不同状态类中。</td><td style="text-align:left;">复杂组件的各种交互状态、网络游戏人物状态。</td></tr><tr><td style="text-align:left;"><strong>职责链模式</strong></td><td style="text-align:left;">“接力赛跑”：一步步往下传，直到有人处理。</td><td style="text-align:left;"><strong>Express/Koa 的中间件 (Middleware)</strong>。</td></tr><tr><td style="text-align:left;"><strong>命令模式</strong></td><td style="text-align:left;">“餐厅点菜单”：动作封装成对象，支持排队和撤销。</td><td style="text-align:left;">文本编辑器的 Undo/Redo、操作录制。</td></tr><tr><td style="text-align:left;"><strong>中介者模式</strong></td><td style="text-align:left;">“机场塔台”：多对多变一对多，集中管理交互。</td><td style="text-align:left;">复杂表单联动、Vuex/Redux。</td></tr><tr><td style="text-align:left;"><strong>迭代器模式</strong></td><td style="text-align:left;">“点名签到”：提供统一遍历方式。</td><td style="text-align:left;"><code>for...of</code> 循环、ES6 的 Generator 生成器。</td></tr><tr><td style="text-align:left;"><strong>模板方法</strong></td><td style="text-align:left;">“考试卷子”：父类定大纲步骤，子类填具体答案。</td><td style="text-align:left;">Vue/React 的<strong>生命周期钩子函数</strong>。</td></tr></tbody></table><h2 id="_2-模式设计的-六大心法-solid-迪米特" tabindex="-1">2. 模式设计的“六大心法” (SOLID + 迪米特) <a class="header-anchor" href="#_2-模式设计的-六大心法-solid-迪米特" aria-label="Permalink to &quot;2. 模式设计的“六大心法” (SOLID + 迪米特)&quot;">​</a></h2><p>在使用上述战术（模式）前，必须牢记这六条战略心法：</p><ol><li><strong>单一职责 (S)</strong>：一个函数/类只做一件事。</li><li><strong>开闭原则 (O)</strong>：对扩展开放，对修改关闭（多用插件和策略，少改老代码）。</li><li><strong>里氏替换 (L)</strong>：子类必须能完美替换父类。</li><li><strong>接口隔离 (I)</strong>：不要强迫别人使用他们不需要的方法。</li><li><strong>依赖倒置 (D)</strong>：依赖抽象接口，不依赖具体实现。</li><li><strong>最少知识 (迪米特)</strong>：只和直接的朋友交谈，不要越级指挥。</li></ol><h2 id="_3-深度实战-faq-如何选择与权衡" tabindex="-1">3. 深度实战 FAQ：如何选择与权衡？ <a class="header-anchor" href="#_3-深度实战-faq-如何选择与权衡" aria-label="Permalink to &quot;3. 深度实战 FAQ：如何选择与权衡？&quot;">​</a></h2><h3 id="_3-1-我记不住这么多模式-怎么办" tabindex="-1">3.1 “我记不住这么多模式，怎么办？” <a class="header-anchor" href="#_3-1-我记不住这么多模式-怎么办" aria-label="Permalink to &quot;3.1 “我记不住这么多模式，怎么办？”&quot;">​</a></h3><ul><li><strong>答</strong>：千万不要死记硬背名字。记住它们<strong>解决的问题</strong>。 <ul><li>看到超长的 <code>if-else</code> ➡️ 想到<strong>策略模式</strong>。</li><li>看到一堆组件互相调用乱成一锅粥 ➡️ 想到<strong>中介者模式</strong>或<strong>发布-订阅</strong>。</li><li>想拦截别人对对象的读写 ➡️ 想到<strong>代理模式</strong>。</li></ul></li></ul><h3 id="_3-2-设计模式会降低性能吗" tabindex="-1">3.2 设计模式会降低性能吗？ <a class="header-anchor" href="#_3-2-设计模式会降低性能吗" aria-label="Permalink to &quot;3.2 设计模式会降低性能吗？&quot;">​</a></h3><ul><li><strong>答</strong>：通常会增加微小的 CPU 计算和内存开销（因为多了一层抽象或闭包）。但在 99% 的前端场景中，这种损耗远低于 DOM 操作带来的损耗。而它们带来的<strong>代码可读性</strong>和<strong>可维护性</strong>的提升，价值无可估量。</li><li><em>例外：享元模式专门用于提升性能。</em></li></ul><h3 id="_3-3-如何避免-过度设计-over-engineering" tabindex="-1">3.3 如何避免“过度设计 (Over-engineering)”？ <a class="header-anchor" href="#_3-3-如何避免-过度设计-over-engineering" aria-label="Permalink to &quot;3.3 如何避免“过度设计 (Over-engineering)”？&quot;">​</a></h3><ul><li><strong>判断标准</strong>：如果你的业务逻辑一眼就能看懂，且未来几乎不会改变，直接写过程式代码！不要为了用模式而用模式，把 10 行代码写成 100 行。</li><li><strong>黄金法则</strong>：当痛苦出现时（代码已经改不动了，出现坏味道了），再进行重构引入设计模式。也就是**“事不过三”原则**（同样的重复代码出现第三次时，必须重构）。</li></ul><h3 id="_3-4-vue-react-开发者最需要掌握哪几个" tabindex="-1">3.4 Vue/React 开发者最需要掌握哪几个？ <a class="header-anchor" href="#_3-4-vue-react-开发者最需要掌握哪几个" aria-label="Permalink to &quot;3.4 Vue/React 开发者最需要掌握哪几个？&quot;">​</a></h3><ul><li><strong>代理/观察者/发布-订阅</strong>：这是理解框架响应式原理的基础。如果不懂这些，你永远只是一个 API 使用者，而不是工程师。</li><li><strong>策略模式</strong>：这是日常业务开发中用来优化烂代码最锋利的刀。</li><li><strong>装饰器模式</strong>：深入理解 HOC（高阶组件）的本质。</li></ul>',24)])])}const y=a(s,[["render",o]]);export{h as __pageData,y as default};
//# sourceMappingURL=designPatterns_summary_patternSummarize.md.DM7csCkh.js.map
